import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithRecordSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        String newSeparator = "\n";
        CSVFormat modified = original.withRecordSeparator(newSeparator);

        assertNotNull(modified);
        assertEquals(newSeparator, modified.getRecordSeparator());
        // Original remains unchanged
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), original.getRecordSeparator());

        // Test with null separator using withRecordSeparator(Character) to avoid ambiguity
        CSVFormat nullSeparatorFormat = original.withRecordSeparator((Character) null);
        assertNull(nullSeparatorFormat.getRecordSeparator());

        // Test with empty string separator
        CSVFormat emptySeparatorFormat = original.withRecordSeparator("");
        assertEquals("", emptySeparatorFormat.getRecordSeparator());

        // Test with multi-char separator
        String multiCharSeparator = "\r\n\r";
        CSVFormat multiCharFormat = original.withRecordSeparator(multiCharSeparator);
        assertEquals(multiCharSeparator, multiCharFormat.getRecordSeparator());
    }
}
